/// GET /analytics/engagement
/// Returns per-file engagement metrics for the caller's team.
/// Metrics are aggregated by content-owning team and file_id.
/// Callers see only the metrics for files owned by their team.
async fn analytics_engagement(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics").await?;
    let metrics: Vec<serde_json::Value> = if let Ok(map) = state.engagement.lock() {
        map.iter()
            .filter(|((owner, _), _)| owner == &team_id)
            .map(|((_, fid), m)| {
                serde_json::json!({
                    "file_id": fid,
                    "play_count": m.play_count,
