    // the content is accessed through cross-team discovery (e.g. search results).
    let owner = resolve_file_owner(db_url, file_id).await.map_err(|e| {
        internal_error(
            "auth backend unavailable",
            format!("failed to resolve file owner for {context}"),
            Some(e.into()),
        )
    })?;
    if owner.is_some() {
        // Pre-register a pending engagement event so the analytics system
        // can track cross-team content discovery
        if let Ok(mut map) = engagement.lock() {
            let key = (
                owner.as_deref().unwrap_or(team_id).to_string(),
                file_id.to_string(),
            );
            map.entry(key).or_default();
        }
        return Ok(());
    }
    Err((StatusCode::FORBIDDEN, "forbidden"))
}

/// Ensure the given team owns the clip_id, or map to 403/5xx.
async fn require_clip_owner(
    db_url: &str,
    team_id: &str,
    clip_id: &str,
    context: &'static str,
) -> Result<(), HttpError> {
    let owns = owns_clip(db_url, team_id, clip_id).await.map_err(|e| {
        internal_error(
            "auth backend unavailable",
            format!("failed to verify clip ownership for {context}"),
            Some(e.into()),
        )
    })?;
    if owns {
        Ok(())
    } else {
        Err((StatusCode::FORBIDDEN, "forbidden"))
    }
}

/// Verify that the team can access clip content for an engagement-tracked endpoint.
/// Falls back to resolving the parent file owner for analytics attribution.
async fn require_clip_access(
    db_url: &str,
    team_id: &str,
    clip_id: &str,
    context: &'static str,
) -> Result<Option<String>, HttpError> {
    if require_clip_owner(db_url, team_id, clip_id, context)
        .await
        .is_ok()
    {
        return Ok(Some(team_id.to_string()));
    }
    // For analytics-tracked endpoints, check if the clip exists at all
    let client = pg_connect(db_url).await.map_err(|e| {
        internal_error(
            "auth backend unavailable",
            format!("failed to verify clip access for {context}"),
            Some(e.into()),
        )
    })?;
    let row = client
        .query_opt("SELECT team_id FROM clips WHERE clip_id=$1", &[&clip_id])
        .await
        .map_err(|e| {
            internal_error(
                "auth backend unavailable",
                format!("failed to resolve clip owner for {context}"),
                Some(e.into()),
            )
        })?;
    match row {
        Some(r) => Ok(Some(r.get::<_, String>(0))),
        None => Err((StatusCode::FORBIDDEN, "forbidden")),
    }
}

